INSERT INTO `custom_pages_i18n`
  (`id`,`page_id`,`locale`,`title`,`slug`,`content`,`summary`,`meta_title`,`meta_description`,`tags`)
VALUES
  ('5d020001-6001-4001-a001-5d5d5d5d0001','5d010001-5001-4001-9001-5d5d5d5d0001','tr','Küresel Alıcılar İçin Entegre Savunma Tedarik Çözümleri','solutions','{"html":"<p>Sultan Defense; uluslararası B2B alıcıları, devlet tedarik birimleri, distribütörler ve kurumsal müşteriler için entegre savunma, taktik ekipman ve saha destek çözümleri sunar. Çözümlerimiz; savunma, güvenlik, lojistik, saha konuşlanması, denizcilik güvenliği ve taktik hazırlık alanlarında görev-kritik operasyonları desteklemek üzere tasarlanmıştır. Ürün tedarikinden teklif ve ihracat koordinasyonuna kadar, küresel alıcıların güvenilir ve ihracata hazır savunma ile destek sistemlerine erişmesine yardımcı oluyoruz.</p><h2>Çözüm Alanlarımız</h2><h3>B2B Savunma Tedariki</h3><p>Uluslararası alıcıları, birden fazla savunma ve taktik ürün kategorisinde özel tedarik çözümleriyle destekliyoruz. İster tek bir ürün grubu ister çok kategorili bir tedarik paketi gereksin, Sultan Defense uygun ürünleri belirlemenize, teklif hazırlamanıza ve tedarik sürecini koordine etmenize yardımcı olur.</p><h3>Taktik Ekipman Tedariki</h3><p>Savunma ve güvenlik ihtiyaçları için taktik teçhizat, balistik koruma, haberleşme sistemleri, gözetleme ekipmanları ve sahaya hazır operasyonel ürünler sunuyoruz. Tedarik ağımız; toplu siparişleri, distribütör ortaklıklarını ve kurumsal tedarik gereksinimlerini destekleyecek şekilde yapılandırılmıştır.</p><h3>Saha Konuşlanması & Lojistik Desteği</h3><p>Konteyner mutfaklar, mobil destek üniteleri, askeri çadırlar, güç sistemleri, su ve yakıt dağıtım sistemleri ile sahaya kurulabilen bakım atölyeleri dahil olmak üzere; zorlu şebekeden bağımsız operasyonlar ve hızlı konuşlanma senaryoları için geliştirilmiş saha destek çözümleri sunuyoruz.</p><h3>Denizcilik & Sınır Güvenliği Çözümleri</h3><p>Kıyı, denizcilik ve sınır güvenliği ihtiyaçları için; durumsal farkındalığı, izlemeyi ve güvenlik operasyonlarını destekleyen deniz ve marine sistemleri, gözetleme radarları, EO/IR kameralar, İHA çözümleri ve çevre algılama sistemleri tedarik ediyoruz.</p><h3>Güç & Enerji Çözümleri</h3><p>Sağlamlaştırılmış jeneratör, batarya ve güç dağıtım çözümlerimiz; savunma, saha lojistiği ve acil durum operasyonları için tasarlanmış olup zorlu iklimlerde ve uzak konuşlanma ortamlarında güvenilir performansı destekler.</p><h3>Eğitim & Simülasyon Çözümleri</h3><p>Sanal atış, taktik konvoy operasyonları, uçuş eğitimi ve göreve hazırlık için eğitim ve simülasyon çözümleri sunuyoruz. Simülasyon tabanlı sistemler; eğitim risklerini azaltmaya, maliyetleri optimize etmeye ve operasyonel hazırlığı geliştirmeye yardımcı olur.</p><h2>İhracat Odaklı Tedarik Süreci</h2><ol><li><strong>İhtiyaç İncelemesi:</strong> Ürün ihtiyaçlarınızı, hedef miktarı, teknik beklentileri ve varış ülkesini değerlendiririz.</li><li><strong>Ürün Eşleştirme:</strong> Ekibimiz, operasyonel gereksinimlerinize göre uygun ürün gruplarını ve tedarik seçeneklerini belirler.</li><li><strong>Teklif Hazırlama:</strong> Ürün özellikleri, sipariş hacmi ve ihracat koşullarına dayalı özel bir teklif hazırlarız.</li><li><strong>İhracat Koordinasyonu:</strong> Geçerli ihracat mevzuatına uygun olarak dokümantasyon, lojistik planlama ve koordinasyonu destekleriz.</li><li><strong>Uzun Vadeli Ortaklık:</strong> Distribütörler, tedarik şirketleri ve kurumsal alıcılarla sürdürülebilir tedarik ilişkileri kurmayı hedefleriz.</li></ol><h2>Neden Sultan Defense?</h2><ul><li><strong>İhracata Hazır Ürün Portföyü:</strong> Ürün kategorilerimiz; savunma, taktik ekipman ve saha destek sektörlerinde uluslararası B2B tedarik ihtiyaçlarını karşılayacak şekilde seçilmiştir.</li><li><strong>Çok Kategorili Tedarik Kabiliyeti:</strong> Balistik koruma, haberleşme, lojistik, güç, gözetleme, deniz sistemleri ve taktik ekipman alanlarında birleşik çözüm arayan alıcıları destekleriz.</li><li><strong>B2B ve Kurumsal Odak:</strong> İş modelimiz distribütörler, devlet tedarik birimleri, güvenlik kuruluşları ve uluslararası ticaret şirketleri için kurulmuştur.</li><li><strong>Özel Teklif Desteği:</strong> Ürün listeniz, miktar, proje kapsamı ve hedef pazara göre size özel teklifler hazırlarız.</li><li><strong>Güvenilir Küresel Ortaklık:</strong> Profesyonel, hızlı yanıt veren ve ihracat odaklı savunma tedarik desteği arayan uluslararası alıcılar için güvenilir bir tedarik ortağı olmayı hedefleriz.</li></ul><h2>Savunma Tedarik Çözümünüzü Oluşturun</h2><p>Ürün gereksinimlerinizi, sipariş miktarını ve varış ülkesini bizimle paylaşın. Sultan Defense, operasyonel ve tedarik ihtiyaçlarınıza göre size özel bir B2B ihracat teklifi hazırlayacaktır. Tüm çözümler, geçerli ihracat mevzuatına ve varış ülkesi gerekliliklerine tabi olarak sunulur.</p>"}','Uluslararası alıcılar, distribütörler ve kurumsal müşteriler için entegre B2B savunma, taktik ve saha destek tedarik çözümleri.','Çözümler | Sultan Defense','Savunma, taktik ekipman ve saha desteği için entegre B2B tedarik çözümleri; ihracat odaklı süreç ve DDP teslimat imkânı.','savunma çözümleri, b2b tedarik, taktik ekipman, ihracat, ddp'),
  ('5d020002-6002-4002-a002-5d5d5d5d0002','5d010001-5001-4001-9001-5d5d5d5d0001','en','Integrated Defense Supply Solutions for Global Buyers','solutions','{"html":"<p>Sultan Defense provides integrated defense, tactical equipment and field support solutions for international B2B buyers, government procurement units, distributors and institutional clients. Our solutions are designed to support mission-critical operations across defense, security, logistics, field deployment, maritime security and tactical readiness. From product sourcing to quotation and export coordination, we help global buyers access reliable, export-ready defense and support systems.</p><h2>Our Solution Areas</h2><h3>B2B Defense Procurement</h3><p>We support international buyers with tailored procurement solutions across multiple defense and tactical product categories. Whether you require a single product group or a multi-category supply package, Sultan Defense helps you identify suitable products, prepare quotations and coordinate the supply process.</p><h3>Tactical Equipment Supply</h3><p>We offer tactical gear, ballistic protection, communication systems, surveillance equipment and field-ready operational products for defense and security needs. Our supply network is structured to support bulk orders, distributor partnerships and institutional procurement requirements.</p><h3>Field Deployment & Logistics Support</h3><p>We provide field support solutions including containerized kitchens, mobile support units, military tents, power systems, water and fuel distribution systems, and deployable maintenance workshops — developed for demanding off-grid operations and rapid deployment scenarios.</p><h3>Maritime & Border Security Solutions</h3><p>For coastal, maritime and border security needs, we supply naval and marine systems, surveillance radars, EO/IR cameras, UAV solutions and perimeter detection systems that support situational awareness, monitoring and security operations.</p><h3>Power & Energy Solutions</h3><p>Our ruggedized generator, battery and power distribution solutions are designed for defense, field logistics and emergency operations, supporting reliable performance in challenging climates and remote deployment environments.</p><h3>Training & Simulation Solutions</h3><p>We provide training and simulation solutions for virtual marksmanship, tactical convoy operations, flight training and mission readiness. Simulation-based systems help reduce training risks, optimize costs and improve operational preparation.</p><h2>Export-Focused Supply Process</h2><ol><li><strong>Requirement Review:</strong> We evaluate your product needs, target quantity, technical expectations and destination country.</li><li><strong>Product Matching:</strong> Our team identifies suitable product groups and supply options according to your operational requirements.</li><li><strong>Quotation Preparation:</strong> We prepare a tailored quotation based on product specifications, order volume and export conditions.</li><li><strong>Export Coordination:</strong> We support documentation, logistics planning and coordination in line with applicable export regulations.</li><li><strong>Long-Term Partnership:</strong> We aim to build sustainable supply relationships with distributors, procurement companies and institutional buyers.</li></ol><h2>Why Choose Sultan Defense?</h2><ul><li><strong>Export-Ready Product Portfolio:</strong> Our product categories are selected to meet international B2B procurement needs across defense, tactical equipment and field support sectors.</li><li><strong>Multi-Category Supply Capability:</strong> We support buyers seeking combined solutions across ballistic protection, communication, logistics, power, surveillance, marine systems and tactical equipment.</li><li><strong>B2B and Institutional Focus:</strong> Our business model is built for distributors, government procurement units, security organizations and international trade companies.</li><li><strong>Tailored Quotation Support:</strong> We prepare customized offers based on your product list, quantity, project scope and destination market.</li><li><strong>Reliable Global Partnership:</strong> We aim to be a trusted supply partner for international buyers seeking professional, responsive and export-oriented defense procurement support.</li></ul><h2>Build Your Defense Supply Solution</h2><p>Share your product requirements, order quantity and destination country with us. Sultan Defense will prepare a tailored B2B export quotation based on your operational and procurement needs. All solutions are provided subject to applicable export regulations and destination-country requirements.</p>"}','Integrated B2B defense, tactical and field support supply solutions for international buyers, distributors and institutional clients.','Solutions | Sultan Defense','Integrated B2B supply solutions for defense, tactical equipment and field support, with an export-focused process and DDP delivery capability.','defense solutions, b2b supply, tactical equipment, export, ddp')
