INSERT INTO `custom_pages_i18n`
  (`id`,`page_id`,`locale`,`title`,`slug`,`content`,`summary`,`meta_title`,`meta_description`,`tags`)
VALUES
  ('5d020003-6003-4003-a003-5d5d5d5d0003','5d010002-5002-4002-9002-5d5d5d5d0002','tr','DDP Teslimat İmkânıyla Küresel Savunma İhracatı','export','{"html":"<p>Sultan Defense; uluslararası B2B alıcıları, distribütörler, tedarik şirketleri ve kurumsal müşteriler için ihracat odaklı savunma, taktik ekipman ve saha destek çözümleri sunar. Küresel alıcıları; yapılandırılmış bir ihracat süreci, profesyonel dokümantasyon, uluslararası lojistik koordinasyonu ve uygun ürünler ile onaylı varış ülkeleri için DDP teslimat imkânıyla destekliyoruz. Amacımız; alıcıların Türkiye''den güvenilir savunma ve taktik ürünlere net iletişim, şeffaf teklif ve güvenilir teslimat planlamasıyla erişmesine yardımcı olarak uluslararası tedariki basitleştirmektir.</p><h2>DDP Teslimat İmkânı</h2><p>Sultan Defense, uygun siparişler için Delivered Duty Paid (DDP) teslimat çözümleri sunabilir. DDP teslimat ile; ihracat sürecini, uluslararası taşımayı, ithalat gümrük işlemlerini, geçerli vergi ve resimleri ve mutabık kalınan varış noktasına nihai teslimatı koordine edebiliriz. Bu, uluslararası alıcıların siparişlerini daha basit bir satın alma süreci ve azaltılmış lojistik karmaşıklığıyla almasını sağlar.</p><p>DDP teslimat; ürün sınıflandırması, varış ülkesi mevzuatı, nihai kullanıcı gereksinimleri ve geçerli ihracat kontrol onaylarına tabidir.</p><h2>DDP İhracat Desteğimiz Neler Kapsayabilir?</h2><p>Uygun ürünler ve onaylı pazarlar için DDP teslimat desteğimiz şunları içerebilir:</p><ul><li>İhracat dokümantasyon koordinasyonu</li><li>Uluslararası navlun planlaması</li><li>İthalat gümrük işlemleri koordinasyonu</li><li>Vergi ve resim yönetimi</li><li>Kapıdan kapıya teslimat planlaması</li><li>Sevkiyat takibi ve alıcı iletişimi</li><li>Mutabık kalınan varış noktasına nihai teslimat</li></ul><p>Her sevkiyat; ürün kategorisi, varış ülkesi, sipariş hacmi ve geçerli ticaret mevzuatına göre değerlendirilir.</p><h2>İhracat Pazarları</h2><p>Sultan Defense; Orta Doğu, Afrika, Orta Asya, Balkanlar ve diğer küresel pazarlardaki uluslararası B2B tedarik ihtiyaçlarını destekler. Türkiye''den güvenilir savunma ve taktik ürün tedariki arayan distribütörler, devlet tedarik birimleri, güvenlik kuruluşları, uluslararası ticaret şirketleri ve kurumsal alıcılarla çalışırız.</p><h2>İhracat Dokümantasyonu</h2><p>Ürün türü, varış ülkesi ve sipariş yapısına bağlı olarak Sultan Defense, alıcılara gerekli ihracat ve lojistik dokümantasyonunda destek olabilir; bunlar şunları içerebilir:</p><ul><li>Ticari fatura</li><li>Çeki listesi</li><li>Menşe şahadetnamesi</li><li>Teknik ürün dokümantasyonu</li><li>Taşıma belgeleri</li><li>Gümrükle ilgili belgeler</li><li>Gerektiğinde nihai kullanıcı dokümantasyonu</li><li>Uygulanabilir olduğunda ihracat uyumluluk belgeleri</li></ul><p>Tüm ihracat operasyonları; geçerli yasalar, ürüne özgü gereksinimler ve varış ülkesi mevzuatına uygun olarak değerlendirilir.</p><h2>İhracat Sürecimiz</h2><ol><li><strong>İhtiyaç İncelemesi:</strong> Gerekli ürün kategorisini, miktarı, varış ülkesini, teslimat adresini ve teknik beklentileri paylaşırsınız.</li><li><strong>Ürün & Teslimat Değerlendirmesi:</strong> Ürün mevcudiyetini, ihracat uygunluğunu, varış gereksinimlerini ve DDP teslimat fizibilitesini gözden geçiririz.</li><li><strong>Özel Teklif:</strong> Ürün listeniz, miktar, varış noktası ve teslimat gereksinimlerine göre size özel bir B2B ihracat teklifi hazırlarız.</li><li><strong>Dokümantasyon & Lojistik Koordinasyonu:</strong> Sipariş onaylandığında; ihracat dokümantasyonunu, lojistik planlamayı ve gümrükle ilgili süreçleri koordine ederiz.</li><li><strong>Varış Noktasına Teslimat:</strong> DDP onaylı sevkiyatlar için, mutabık kalınan nihai varış noktasına kadar teslimat sürecini yönetir ve alıcıyı sevkiyat boyunca bilgilendiririz.</li></ol><h2>Neden Sultan Defense ile İhracat?</h2><ul><li><strong>DDP Teslimat Kabiliyeti:</strong> Uygun ürünler ve onaylı ülkeler için DDP teslimat sunarak alıcıların gümrük ve lojistik karmaşıklığını azaltmasına yardımcı oluruz.</li><li><strong>İhracat Odaklı B2B Tedarik:</strong> Operasyonumuz; uluslararası alıcılar, distribütörler, tedarik şirketleri ve kurumsal müşteriler için yapılandırılmıştır.</li><li><strong>Çok Kategorili Ürün Portföyü:</strong> Savunma, taktik, saha destek, lojistik, güç, gözetleme, denizcilik ve eğitim çözümü kategorileri tedarik ederiz.</li><li><strong>Profesyonel Dokümantasyon Desteği:</strong> Ürün ve varış gereksinimlerine göre alıcılara ihracat, lojistik ve gümrük dokümantasyonunda yardımcı oluruz.</li><li><strong>Güvenilir Küresel Ortaklık:</strong> Hızlı iletişim, özel teklifler ve güvenilir ihracat koordinasyonu yoluyla uzun vadeli B2B ortaklıkları kurmayı hedefleriz.</li></ul><h2>İhracat Teklifi Talep Edin</h2><p>Ürün gereksinimlerinizi, sipariş miktarını, varış ülkesini ve teslimat adresini bizimle paylaşın. Sultan Defense talebinizi değerlendirecek ve uygun olduğunda DDP teslimat seçenekleriyle size özel bir ihracat teklifi hazırlayacaktır.</p>"}','Türkiye''den DDP teslimat imkânı, ihracat dokümantasyonu ve uluslararası lojistik koordinasyonuyla ihracat odaklı savunma ve taktik tedarik.','İhracat | Sultan Defense','DDP teslimat, ihracat dokümantasyonu ve lojistik koordinasyonuyla Türkiye''den ihracat odaklı savunma ve taktik ürün tedariki.','savunma ihracatı, ddp, ihracat dokümantasyonu, b2b, lojistik'),
  ('5d020004-6004-4004-a004-5d5d5d5d0004','5d010002-5002-4002-9002-5d5d5d5d0002','en','Global Defense Export with DDP Delivery Capability','export','{"html":"<p>Sultan Defense provides export-focused defense, tactical equipment and field support solutions for international B2B buyers, distributors, procurement companies and institutional clients. We support global buyers with a structured export process, professional documentation, international logistics coordination and DDP delivery capability for eligible products and approved destination countries. Our goal is to simplify international procurement by helping buyers access reliable defense and tactical products from Türkiye with clear communication, transparent quotation and dependable delivery planning.</p><h2>DDP Delivery Available</h2><p>Sultan Defense can provide Delivered Duty Paid (DDP) delivery solutions for eligible orders. With DDP delivery, we can coordinate the export process, international transportation, import customs clearance, applicable duties and taxes, and final delivery to the agreed destination. This allows international buyers to receive their orders with a more simplified purchasing process and reduced logistics complexity.</p><p>DDP delivery is subject to product classification, destination country regulations, end-user requirements and applicable export control approvals.</p><h2>What Our DDP Export Support May Include</h2><p>For eligible products and approved markets, our DDP delivery support may include:</p><ul><li>Export documentation coordination</li><li>International freight planning</li><li>Import customs clearance coordination</li><li>Duties and tax handling</li><li>Door-to-door delivery planning</li><li>Shipment tracking and buyer communication</li><li>Final delivery to the agreed destination</li></ul><p>Each shipment is reviewed according to the product category, destination country, order volume and applicable trade regulations.</p><h2>Export Markets</h2><p>Sultan Defense supports international B2B procurement needs in the Middle East, Africa, Central Asia, the Balkans and other global markets. We work with distributors, government procurement units, security organizations, international trade companies and institutional buyers seeking reliable defense and tactical product supply from Türkiye.</p><h2>Export Documentation</h2><p>Depending on the product type, destination country and order structure, Sultan Defense can support buyers with the required export and logistics documentation, which may include:</p><ul><li>Commercial invoice</li><li>Packing list</li><li>Certificate of origin</li><li>Technical product documentation</li><li>Transport documents</li><li>Customs-related documents</li><li>End-user documentation, when required</li><li>Export compliance documents, when applicable</li></ul><p>All export operations are evaluated in line with applicable laws, product-specific requirements and destination country regulations.</p><h2>Our Export Process</h2><ol><li><strong>Requirement Review:</strong> You share your required product category, quantity, destination country, delivery address and technical expectations.</li><li><strong>Product & Delivery Evaluation:</strong> We review product availability, export eligibility, destination requirements and DDP delivery feasibility.</li><li><strong>Tailored Quotation:</strong> We prepare a customized B2B export quotation based on your product list, quantity, destination and delivery requirements.</li><li><strong>Documentation & Logistics Coordination:</strong> Once the order is confirmed, we coordinate export documentation, logistics planning and customs-related processes.</li><li><strong>Delivery to Destination:</strong> For DDP-approved shipments, we manage the delivery process up to the agreed final destination and keep buyers informed throughout the shipment.</li></ol><h2>Why Export with Sultan Defense?</h2><ul><li><strong>DDP Delivery Capability:</strong> We can provide DDP delivery for eligible products and approved countries, helping buyers reduce customs and logistics complexity.</li><li><strong>Export-Focused B2B Supply:</strong> Our operation is structured for international buyers, distributors, procurement companies and institutional clients.</li><li><strong>Multi-Category Product Portfolio:</strong> We supply defense, tactical, field support, logistics, power, surveillance, maritime and training solution categories.</li><li><strong>Professional Documentation Support:</strong> We assist buyers with export, logistics and customs documentation according to product and destination requirements.</li><li><strong>Reliable Global Partnership:</strong> We aim to build long-term B2B partnerships through responsive communication, tailored quotations and dependable export coordination.</li></ul><h2>Request an Export Quotation</h2><p>Share your product requirements, order quantity, destination country and delivery address with us. Sultan Defense will evaluate your request and prepare a tailored export quotation with DDP delivery options where applicable.</p>"}','Export-focused defense and tactical supply from Türkiye with DDP delivery capability, export documentation and international logistics coordination.','Export | Sultan Defense','Export-focused defense and tactical supply from Türkiye with DDP delivery, export documentation and international logistics coordination.','defense export, ddp, export documentation, b2b, logistics')
