-- Sultan Defense — Solutions + Export sayfaları (custom_pages, TR+EN). Kaynak: Sultan Defense.docx (musteri).
SET NAMES utf8mb4;

-- ===== SOLUTIONS =====
ON DUPLICATE KEY UPDATE `module_key`=VALUES(`module_key`),`is_published`=VALUES(`is_published`),`updated_at`=NOW(3);

ON DUPLICATE KEY UPDATE `title`=VALUES(`title`),`content`=VALUES(`content`),`summary`=VALUES(`summary`),`meta_title`=VALUES(`meta_title`),`meta_description`=VALUES(`meta_description`),`tags`=VALUES(`tags`),`updated_at`=NOW(3);

-- ===== EXPORT =====
ON DUPLICATE KEY UPDATE `module_key`=VALUES(`module_key`),`is_published`=VALUES(`is_published`),`updated_at`=NOW(3);

ON DUPLICATE KEY UPDATE `title`=VALUES(`title`),`content`=VALUES(`content`),`summary`=VALUES(`summary`),`meta_title`=VALUES(`meta_title`),`meta_description`=VALUES(`meta_description`),`tags`=VALUES(`tags`),`updated_at`=NOW(3);
